#!/bin/bash
# Script to create placeholder icons if you don't have them yet
# This creates simple colored squares - replace with your actual logo later

# Create a simple 192x192 PNG (placeholder)
cat > logo192.png.base64 << 'ICONDATA'

ICONDATA
base64 -d logo192.png.base64 > logo192.png
rm logo192.png.base64

# Create 512x512 (scaled from 192)
cp logo192.png logo512.png

echo "Placeholder icons created. Replace with actual Athletics logo later."
